import React from "react";
import swal from "sweetalert";
import { UseForm } from "./UseForm";
import loader from "../sources/grid.svg";
import "../estilos/formulario.css";

function Loader() {
  return (
    <img
      className="loader"
      style={{ width: "20px", margin: "0 auto" }}
      alt="loader"
      src={loader}
    />
  );
}

const inicialForm = {
  nombre: "",
  email: "",
  coments: "",
};

const validateForm = (form, e) => {
  let error = {};
  let regexNombre = /^[A-Za-zÑñÁáÉéÍíÓóÚúÜü\s]+$/,
    regexEmail =
      /^[a-z0-9]+(\.[_a-z0-9]+)*@[a-z0-9-]+(\.[a-z0-9-]+)*(\.[a-z]{2,15})$/,
    regexComents = /^.{1,255}$/;

  if (e?.target.name === "nombre") {
    if (!form.nombre.trim()) {
      error.nombre = "El campo de Nombre es requerido";
    } else if (!regexNombre.test(form.nombre.trim())) {
      error.nombre =
        "El campo de Nombre solo acepta letras y espacios en blanco";
    }
  }
  if (e?.target.name === "email") {
    if (!form.email.trim()) {
      error.email = "El campo de Email es requerido";
    } else if (!regexEmail.test(form.email.trim())) {
      error.email = "Ingrese un email valido para enviar";
    }
  }
  if (e?.target.name === "coments") {
    if (!form.coments.trim()) {
      error.coments = "Escriba un mensaje para enviar";
    } else if (!regexComents.test(form.coments.trim())) {
      error.coments = "No se pueden enviar mensajes de mas de 255 caracteres.";
    }
  }

  return error;
};

function Formulario() {
  const { form, error, res, loading, handleChange, handleBlur, handleSubmit } =
    UseForm(inicialForm, validateForm);

  return (
    <div className="box">
      <div className="conteiner-form">
        <section>
          <h4 className="form-title">Trabajemos juntos en tu proyecto!</h4>
          <p className="form-desc">
            No olvides ingresar tu Email, para contestar tu propuesta.
          </p>
        </section>
        <form onSubmit={handleSubmit}>
          <div className="textarea">
            <input
              type="text"
              name="nombre"
              onBlur={handleBlur}
              onChange={handleChange}
              value={form.nombre}
              required
            />
            <p>Nombre</p>
          </div>
          <div className="textarea">
            <input
              type="email"
              name="email"
              onBlur={handleBlur}
              onChange={handleChange}
              value={form.email}
              required
            />
            <p>Email</p>
          </div>
          <div className="textarea">
            <textarea
              name="coments"
              onBlur={handleBlur}
              onChange={handleChange}
              value={form.coments}
              required
            />
            <p>Mensaje</p>
          </div>
          <input
            type="submit"
            value="Enviar"
            className="hover:text-zinc-900 font-medium rounded hover:bg-fuchsia-500 hover:ring-4 ring-fuchsia-200 hover:-translate-y-1 transition-all hover:shadow-lg hover:shadow-fuchsia-300"
            onSubmit={handleSubmit}
          />
          {loading && <Loader />}
          {error.nombre && <p className="error-input">{error.nombre}</p>}
          {error.email && <p className="error-input">{error.email}</p>}
          {error.coments && <p className="error-input">{error.coments}</p>}
          {res &&
            setTimeout(() => {
              swal(
                "Perfecto!",
                "Su mensaje ha sido enviado con exito",
                "success"
              );
            }, 1000)}
        </form>
      </div>
    </div>
  );
}

export default Formulario;
