import { Canvas } from "@react-three/fiber";
import { Suspense } from "react";
import Textura from "./textura";

// three js

function Mundo() {
  return (
    <div className="mundo">
      <Canvas frameloop="demand">
        <Suspense fallback={null}>
          <Textura />
        </Suspense>
      </Canvas>
    </div>
  );
}

export default Mundo;
