import "../estilos/about.css";
import html from "../sources/html.png";
import css from "../sources/css.png";
import bstp from "../sources/boostrap.png";
import sass from "../sources/sass.png";
import figma from "../sources/figma.png";
import js from "../sources/js.png";
import react from "../sources/react.png";
import git from "../sources/git.png";
import { Bounce } from "react-reveal";
import Tilt from "react-parallax-tilt";

function Aboutme() {
  return (
    <div className="background bg-slate-800 mt-10 shadow-lg border-blue-500 border-solid border-2 rounded">
      <h2
        className="font-semibold mt-5 text-5xl md:text-6xl lg:text-8xl text-teal-50 py-5"
        id="sobremi"
      >
        Habilidades
      </h2>
      <div className="aboutme">
        <Tilt>
          <div className="skills p-10 rounded shadow-lg border-blue-400 border-solid border-2 hover:shadow-xl hover:shadow-blue-400 hover:-translate-y-1 transition-all">
            <div className="porcentaje">
              <img className="img-lang" src={html} alt="" />
              <p className="lang">HTML5</p>
              <div className="conteiner">
                <div className="cantidad"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={css} alt="" />
              <p className="lang">CSS3</p>
              <div className="conteiner">
                <div className="cantidad2"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={bstp} alt="" />
              <p className="lang">BOOTSTRAP</p>
              <div className="conteiner">
                <div className="cantidad3"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={sass} alt="" />
              <p className="lang">SASS</p>
              <div className="conteiner">
                <div className="cantidad4"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={figma} alt="" />
              <p className="lang">FIGMA</p>
              <div className="conteiner">
                <div className="cantidad5"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={js} alt="" />
              <p className="lang">JAVASCRIPT</p>
              <div className="conteiner">
                <div className="cantidad6"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={react} alt="" />
              <p className="lang">REACT</p>
              <div className="conteiner">
                <div className="cantidad7"></div>
              </div>
            </div>
            <div className="porcentaje">
              <img className="img-lang" src={git} alt="" />
              <p className="lang">GIT</p>
              <div className="conteiner">
                <div className="cantidad8"></div>
              </div>
            </div>
          </div>
        </Tilt>
        <div className="about-description">
          <h3 className="title-about">Sobre Mi :</h3>
          <Bounce right cascade>
            <p className="text-justify break-normal text-sm lg:text-lg">
              Me llamo Lucas, soy de Argentina, desarrollo y diseño páginas
              webs, estudie de manera autodidacta y sigo aprendiendo día a día,
              tengo conocimientos en HTML, CSS y JavaScript como base, pero
              maneja muchas otras tecnologías de diseño y desarrollo como lo
              son, Bootstrap, SASS y Figma para el diseño y React, Next y
              Node.js para la programación de las páginas, sigo perfeccionándome
              en estas tecnologías que también me ayudan en el desarrollo de las
              webs que voy realizando. Llevo realizadas algunas webs a clientes,
              y otras que hice por mi cuenta para poner en práctica los
              conocimientos que tengo en el ámbito, aquí abajo dejo mi
              portafolio de trabajos.
            </p>
          </Bounce>
        </div>
      </div>
    </div>
  );
}

export default Aboutme;
