import { OrbitControls } from "@react-three/drei";
import { useLoader } from "@react-three/fiber";
import { AdditiveBlending, DoubleSide, TextureLoader } from "three";
import textura from "../sources/diffuse.jpg";
import textura2 from "../sources/download.jpg";
import textura3 from "../sources/world-line.png";
import textura4 from "../sources/contour1_1.png";
import textura5 from "../sources/contour2_1.png";

function Textura() {
  const [texture, texture2, texture3, texture4, texture5] = useLoader(
    TextureLoader,
    [textura, textura2, textura3, textura4, textura5]
  );
  return (
    <>
      <ambientLight color={"#A20098"} intensity={1} />
      <pointLight position={[8, 8, 8]} />
      <directionalLight color={"#A20098"} position={[8, 8, 8]} />
      <mesh scale={3}>
        <sphereBufferGeometry args={[1, 58, 58]} />
        <meshBasicMaterial
          opacity={0.5}
          transparent={true}
          color={"#007ACC"}
        />
        <OrbitControls maxDistance={20} minDistance={6} autoRotate />
      </mesh>
      <mesh scale={3}>
        <sphereBufferGeometry args={[1, 64, 64, 0, 3.1415925]} />
        <meshBasicMaterial
          opacity={0.7}
          map={texture4}
          transparent={true}
          color={"#007ACC"}
        />
        <OrbitControls maxDistance={20} minDistance={6} autoRotate />
      </mesh>
      <mesh scale={3}>
        <sphereBufferGeometry args={[1, 64, 64, 3.1415925, 3.1415925]} />
        <meshBasicMaterial
          opacity={0.7}
          map={texture5}
          transparent={true}
          color={"#A20098"}
        />
        <OrbitControls maxDistance={20} minDistance={6} autoRotate />
      </mesh>
    </>
  );
}

export default Textura;
