/* eslint-disable jsx-a11y/anchor-is-valid */
import logo from "../sources/logo-large.png";
import logoSm from "../sources/logo-sm.png";
import "../estilos/navegador.css";
import { useEffect, useRef, useState } from "react";

function Navegador() {
  const [width, setWidth] = useState(window.innerWidth);
  const [scroll, setScroll] = useState(window.scrollY);
  const menu = useRef();

  const AbrirMenu = () => {
    menu.current.style.transform = "none";
    document.body.style.overflowY = "hidden";
  };
  const CerrarMenu = () => {
    menu.current.style.transform = "translate(-100%)";
    document.body.style.overflowY = "scroll";
  };
  const ScrollTop = () => {
    window.scrollTo(0, 0);
  };
  useEffect(() => {
    let elementId = document.getElementById("nav");
    document.addEventListener("scroll", () => {
      if (window.scrollY > 170) {
        elementId.classList.add("is-sticky");
      } else {
        elementId.classList.remove("is-sticky");
      }
    });
    const updateWidth = () => {
      const newWidth = window.innerWidth;
      setWidth(newWidth);
    };
    const updateScroll = () => {
      const newScroll = window.scrollY;
      setScroll(newScroll);
    };
    window.addEventListener("resize", () => {
      updateWidth();
      return () => window.removeEventListener("resize", updateWidth);
    });
    window.addEventListener("scroll", () => {
      updateScroll();
      return () => window.removeEventListener("scroll", updateScroll);
    });
  }, [width]);

  return (
    <>
      <div className="nav" id="nav">
        <a href="/">
          {width > 768 && <img className="logo" src={logo} alt="logo,imagen" />}
          {width < 768 && (
            <img className="logo-sm" src={logoSm} alt="logo,imagen" />
          )}
        </a>
        {width > 768 && (
          <div className="links">
            <a data-text="SobreMi" className="enlaces" href="#sobremi">
              <span className="actual-text">&nbsp;Sobre Mi&nbsp;</span>
              <span className="hover-text" aria-hidden="true">
                &nbsp;Sobre&nbsp;Mi&nbsp;
              </span>
            </a>
            <a data-text="MisTrabajos" className="enlaces" href="#trabajos">
              <span className="actual-text">&nbsp;Mis Trabajos&nbsp;</span>
              <span className="hover-text" aria-hidden="true">
                &nbsp;Mis&nbsp;Trabajos&nbsp;
              </span>
            </a>
            <a data-text="Contactame" className="enlaces" href="#contactame">
              <span className="actual-text">&nbsp;Contactame&nbsp;</span>
              <span className="hover-text" aria-hidden="true">
                &nbsp;Contactame&nbsp;
              </span>
            </a>
          </div>
        )}
        {width < 768 && (
          <div>
            <span
              onClick={AbrirMenu}
              className="bars material-symbols-outlined"
            >
              menu
            </span>
          </div>
        )}
        <div ref={menu} className="links-rsp">
          <a onClick={CerrarMenu} className="enlaces" href="#sobremi">
            Sobre mi
          </a>
          <a onClick={CerrarMenu} className="enlaces" href="#trabajos">
            Mis trabajos
          </a>
          <a onClick={CerrarMenu} className="enlaces" href="#contactame">
            Contactame
          </a>
          <span
            onClick={CerrarMenu}
            className="close material-symbols-outlined"
          >
            close
          </span>
        </div>
      </div>
      {scroll > 500 && (
        <div className="uper-conteiner">
          <i href="#" onClick={ScrollTop}>
            <span className="uper material-symbols-outlined">
              arrow_drop_up
            </span>
          </i>
        </div>
      )}
    </>
  );
}

export default Navegador;
