import "../estilos/portafolio.css";
import grafica from "../sources/grafica.png";
import conecty from "../sources/conecty.jpeg";
import html from "../sources/html.png";
import css from "../sources/css.png";
import js from "../sources/js.png";
import next from "../sources/nextjs.png";
import bst from "../sources/boostrap.png";
import react from "../sources/react.png";
import wifnix from "../sources/wifnix-home.png";
import carro from "../sources/carrodecompras.jpeg";
import node from "../sources/node.png";
import portf from "../sources/primerportf.jpeg";
import wpPortf from "../sources/portafolio-wp.jpeg";
import wp from "../sources/wordpress.png";
import { Slide } from "react-reveal";
import Card from "./card";
import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay, Pagination } from "swiper";
import "swiper/css";
import "swiper/css/pagination";

function Works() {
  const pagination = {
    clickable: true,
    renderBullet: function (index, className) {
      return '<span class="' + className + '">' + (index + 1) + "</span>";
    },
  };
  return (
    <>
      <h2 className="titulo-portafolio py-10" id="trabajos">
        Portafolio
      </h2>
      <div className="conteiner-works shadow-lg border-2 border-blue-600">
        <Swiper
          pagination={pagination}
          slidesPerView={1}
          className="MySwiper"
          spaceBetween={30}
          modules={[Pagination, Autoplay]}
          autoplay={{
            delay: 4000,
            disableOnInteraction: true,
          }}
          breakpoints={{
            0: {
              slidesPerView: 1,
            },
            576: {
              slidesPerView: 1,
            },
            768: {
              slidesPerView: 2,
            },
            992: {
              slidesPerView: 3,
            },
            1024: {
              slidesPerView: 3,
            },
          }}
        >
          <SwiperSlide>
            <Card
              background="conecty"
              tittle="Conecty IoT."
              url="https://conecty.com.ar/"
              descripcion="Fui parte del desarrollo de este sitio web, realizado con next
                js, para Eywa, una empresa Argentina. Contiene funcion
                multi-idioma, optimizada y SEO incluido."
              tecs={css}
              tecs1={bst}
              tecs2={js}
              tecs3={next}
            />
          </SwiperSlide>
          <SwiperSlide>
            <Card
              background="wifnix"
              tittle="Wifnix"
              url="https://wifnix.com/"
              descripcion="Pagina web para compañia Puertorriqueña que ofrece servicios de
          IT, Network, CCTV, Diseño Web y mucho mas. Contiene un modal con
          sus redes, y funcion multi idioma."
              tecs={html}
              tecs1={css}
              tecs2={js}
            />
          </SwiperSlide>
          <SwiperSlide>
            <Card
              background="grafica"
              tittle="Grafica FyC"
              url="https://grafica-fyc.netlify.app/"
              descripcion="Landing page para empresa de grafica e impresion de carteles
            para negocios enfocado en la publicidad visual a través
            decartelería, folletería. Contiene la API de instagram para
            mostrar el feed."
              tecs={html}
              tecs1={css}
              tecs2={js}
              tecs3={react}
            />
          </SwiperSlide>
          <SwiperSlide>
            <Card
              background="wordpress"
              tittle="Portafolio WordPress"
              url="http://lucas-practicas.com.ar/"
              descripcion="Mi portafolio realizado a travez de una plantilla de WordPress."
              tecs={wp}
            />
          </SwiperSlide>
          <SwiperSlide>
            <Card
              background="portf"
              tittle="Portafolio Web SPA"
              url="https://lucas-caceres-w.github.io/Black-Hack-web/"
              descripcion="
                Este portafolio, es una SPA (Single Page Aplicatión), realizado
                puramente con Javascript, sin frameworks."
              tecs={html}
              tecs1={css}
              tecs2={js}
            />
          </SwiperSlide>
          <SwiperSlide>
            <Card
              background="carro"
              tittle="Carro de compras"
              url="https://lucas-caceres-w.github.io/Carro-de-compras/"
              descripcion="
                Sistema de carro de compras para e-commerse realizado con react
                js, con el que se puede sumar al carro eliminar y reducir
                productos"
              tecs={html}
              tecs1={css}
              tecs2={js}
            />
          </SwiperSlide>
        </Swiper>
      </div>
    </>
  );
}

export default Works;
