import "../estilos/hero.css";
import Typed from "react-typed";
import { Fade } from "react-reveal";
import Mundo from "./Mundo";

function Hero() {
  return (
    <section className="">
      <div className="hero flex flex-row justify-around items-center pt-12 mb-24 h-full md:h-auto lg:h-screen pb-10">
        <Fade right duration={2000}>
          <div className="titulos w-full text-left ml-5">
            <h1 className="hero-title text-4xl font-semibold text-fuchsia-700 ml-10 w-full lg:text-6xl md:text-3xl">
              <Typed
                loop
                strings={[
                  "Lucas Dev",
                  "React and Next",
                  "<i>Landing Pages</i>",
                  "<i>Promociónate</i>",
                ]}
                typeSpeed={50}
              />
            </h1>
            <h2 className="text-lg ml-10 w-full text-teal-50 lg:text-xl md:text-lg">
              Desarrollador web Frontend
            </h2>
            <a href="#trabajos" className="w-full">
              <button
                className="w-24 md:w-24 lg:w-48 text-center bg-inherit border-2 p-2 mt-5 ml-10 border-fuchsia-600 text-teal-50 rounded hover:text-zinc-900 font-medium hover:bg-fuchsia-500 hover:ring-2 ring-fuchsia-400 hover:-translate-y-1 transition-all hover:shadow-lg hover:shadow-fuchsia-400"
                value="portafolio"
              >
                Portafolio
              </button>
            </a>
          </div>
        </Fade>
        <Fade bottom duration={2000}>
          {/* <div className="mr-5">
            <img
              className="w-48 sm:w-80 md:w-80 lg:w-full"
              src={png}
              alt="web,portafolio"
            />
          </div> */}
          <Mundo />
        </Fade>
      </div>
    </section>
  );
}

export default Hero;
