import Tilt from "react-parallax-tilt";

function Card(props) {
  return (
    <Tilt className="">
      <div className="relative rounded pagina">
        <div
          className={`hov rounded ${props.background} gap-3 bg-cover flex flex-col justify-around`}
        >
          <div className="z-10 title-content ">
            <h3 className="font-bold text-xl text-fuchsia-500 drop-shadow-2xl">{props.tittle}</h3>
            <hr className="" />
          </div>
          <div className="gradiente2 text-sm text-stone-900 drop-shadow-2xl font-medium z-10 card-info">
            {props.descripcion}
            <div className="intro mt-6">
              <a
                className="text-blue-400 italic bg-blue-900 p-3 px-6 rounded transition-colors hover:bg-blue-500 hover:text-blue-900 hover:ring-2 hover:ring-blue-600"
                target="_blank"
                rel="noreferrer noopener"
                href={props.url}
              >
                Visitar
              </a>
            </div>
          </div>
          <div className="gradiente1 z-10 utility-info">
            <ul className="flex justify-around row">
              <img className="w-9 h-9" src={props.tecs} />
              <img className="w-9 h-9" src={props.tecs1} />
              <img className="w-9 h-9" src={props.tecs2} />
              <img className="w-9 h-9" src={props.tecs3} />
            </ul>
          </div>
        </div>
        <div className="gradiente bg-gradient-to-t from-blue-200/80 to-blue-900/90 absolute h-full w-full"></div>
      </div>
    </Tilt>
  );
}

export default Card;
